#!/usr/bin/env node
// Generated by copilot-cli-cost installer v1 when copied to a user launcher directory.
import { spawnSync } from "node:child_process";
import fs from "node:fs";
import path from "node:path";
import process from "node:process";
import { fileURLToPath } from "node:url";

const scriptDirectory = path.dirname(fileURLToPath(import.meta.url));
const fallbackStatusline = path.resolve(scriptDirectory, "..", "src", "cli", "statusline.js");
const fallbackInstalledPluginsDirectory = process.env.COPILOT_COST_STATUSLINE_FALLBACK_ROOT;

main();

function main() {
  const raw = readStdin();
  const payload = parsePayload(raw);
  const statuslineScript = findWorkspaceStatusline(payload) ?? findFallbackStatusline();
  if (!statuslineScript) {
    debug("no statusline implementation found");
    return;
  }

  const result = spawnSync(process.execPath, [statuslineScript, ...process.argv.slice(2)], {
    encoding: "utf8",
    input: raw,
    stdio: ["pipe", "pipe", "pipe"],
    windowsHide: true
  });

  if (result.stdout) {
    process.stdout.write(result.stdout);
  }
  if (result.stderr && process.env.COPILOT_COST_STATUSLINE_DEBUG === "true") {
    process.stderr.write(result.stderr);
  }
  if (result.error) {
    debug(`statusline launcher failed: ${result.error.message}`);
    process.exitCode = 1;
    return;
  }
  process.exitCode = result.status ?? 0;
}

function readStdin() {
  try {
    return fs.readFileSync(0, "utf8");
  } catch {
    return "";
  }
}

function parsePayload(raw) {
  if (!raw.trim()) {
    return {};
  }
  try {
    const payload = JSON.parse(raw);
    return payload && typeof payload === "object" && !Array.isArray(payload) ? payload : {};
  } catch (error) {
    debug(`could not parse statusline payload: ${error.message}`);
    return {};
  }
}

function findWorkspaceStatusline(payload) {
  if (process.env.COPILOT_COST_STATUSLINE_DISABLE_WORKSPACE === "true") {
    return undefined;
  }

  for (const startDirectory of candidateStartDirectories(payload)) {
    const repositoryRoot = findRepositoryRoot(startDirectory);
    if (!repositoryRoot) {
      continue;
    }

    const candidate = path.join(repositoryRoot, "src", "cli", "statusline.js");
    if (path.resolve(candidate) !== path.resolve(fallbackStatusline) && fs.existsSync(candidate)) {
      return candidate;
    }
  }

  return undefined;
}

function findFallbackStatusline() {
  if (fallbackInstalledPluginsDirectory) {
    return findInstalledStatusline(fallbackInstalledPluginsDirectory);
  }
  return fs.existsSync(fallbackStatusline) ? fallbackStatusline : undefined;
}

function findInstalledStatusline(installedPluginsDirectory) {
  if (!fs.existsSync(installedPluginsDirectory)) {
    return undefined;
  }

  const candidates = findFiles(installedPluginsDirectory, "package.json")
    .map((packagePath) => path.dirname(packagePath))
    .filter(isCopilotCostRepository)
    .map((repositoryRoot) => path.join(repositoryRoot, "src", "cli", "statusline.js"));
  candidates.sort(compareFallbackStatuslines);
  return candidates[0];
}

function compareFallbackStatuslines(left, right) {
  const leftMtime = fs.statSync(left).mtimeMs;
  const rightMtime = fs.statSync(right).mtimeMs;
  if (leftMtime !== rightMtime) {
    return rightMtime - leftMtime;
  }
  return left.localeCompare(right);
}

function findFiles(directory, fileName) {
  const results = [];
  const stack = [directory];
  while (stack.length > 0) {
    const current = stack.pop();
    for (const entry of fs.readdirSync(current, { withFileTypes: true })) {
      const fullPath = path.join(current, entry.name);
      if (entry.isDirectory()) {
        stack.push(fullPath);
      } else if (entry.isFile() && entry.name === fileName) {
        results.push(fullPath);
      }
    }
  }
  return results;
}

function candidateStartDirectories(payload) {
  const candidates = [
    payload.workspace?.current_dir,
    payload.cwd,
    process.cwd()
  ];
  return candidates
    .filter((candidate) => typeof candidate === "string" && candidate.trim())
    .map((candidate) => path.resolve(candidate));
}

function findRepositoryRoot(startDirectory) {
  let current = fs.existsSync(startDirectory) && fs.statSync(startDirectory).isFile()
    ? path.dirname(startDirectory)
    : startDirectory;
  while (current && current !== path.dirname(current)) {
    if (isCopilotCostRepository(current)) {
      return current;
    }
    current = path.dirname(current);
  }
  return undefined;
}

function isCopilotCostRepository(directory) {
  const packagePath = path.join(directory, "package.json");
  const statuslinePath = path.join(directory, "src", "cli", "statusline.js");
  if (!fs.existsSync(packagePath) || !fs.existsSync(statuslinePath)) {
    return false;
  }

  try {
    const packageJson = JSON.parse(fs.readFileSync(packagePath, "utf8"));
    return packageJson.name === "copilot-cli-cost";
  } catch {
    return false;
  }
}

function debug(message) {
  if (process.env.COPILOT_COST_STATUSLINE_DEBUG === "true") {
    process.stderr.write(`copilot-cost-statusline: ${message}\n`);
  }
}
